  1→//! Filesystem tools: read, write, list, glob, grep.
  2→//!
  3→//! All operations are confined to the workspace root via [`FsPolicy`].
  4→
  5→use crate::edit::render_hashed_content;
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use praxis_core::workspace::FsPolicy;
 10→use regex::Regex;
 11→use serde_json::json;
 12→use std::fs;
 13→use std::io::{BufRead, BufReader};
 14→use std::path::{Path, PathBuf};
 15→
 16→// ── ReadFileTool ─────────────────────────────────────────────────────
 17→
 18→/// Reads a file and returns content with hashline tags for editing.
 19→pub struct ReadFileTool {
 20→    policy: FsPolicy,
 21→}
 22→
 23→impl ReadFileTool {
 24→    pub fn new(policy: FsPolicy) -> Self {
 25→        Self { policy }
 26→    }
 27→}
 28→
 29→impl Tool for ReadFileTool {
 30→    fn definition(&self) -> ToolDefinition {
 31→        ToolDefinition {
 32→            name: "read_file".into(),
 33→            description: "Reads a file from the filesystem. Returns content with line numbers and hashes for editing.".into(),
 34→            input_schema: json!({
 35→                "type": "object",
 36→                "properties": {
 37→                    "path": { "type": "string", "description": "Path to the file" }
 38→                },
 39→                "required": ["path"]
 40→            }),
 41→            title: Some("Read File".into()),
 42→            output_schema: None,
 43→            annotations: Some(ToolAnnotations {
 44→                read_only: true,
 45→                idempotent: true,
 46→                ..Default::default()
 47→            }),
 48→            category: Some("filesystem".into()),
 49→            tags: vec!["fs".into(), "read".into()],
 50→            timeout_secs: Some(30),
 51→        }
 52→    }
 53→
 54→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
 55→        let path_str = call
 56→            .input
 57→            .get("path")
 58→            .and_then(|v| v.as_str())
 59→            .ok_or_else(|| ToolError::InvalidInput {
 60→                message: "Missing or invalid 'path' argument".into(),
 61→            })?;
 62→
 63→        let path = self
 64→            .policy
 65→            .resolve_existing(Path::new(path_str))
 66→            .map_err(|e| ToolError::ExecutionFailed {
 67→                tool_name: "read_file".into(),
 68→                message: e.to_string(),
 69→            })?;
 70→
 71→        let content = fs::read_to_string(&path).map_err(|e| ToolError::ExecutionFailed {
 72→            tool_name: "read_file".into(),
 73→            message: format!("Failed to read file: {e}"),
 74→        })?;
 75→
 76→        let hashed_content = render_hashed_content(&content);
 77→
 78→        Ok(ToolResult {
 79→            call_id: call.call_id.clone(),
 80→            tool_name: call.tool_name.clone(),
 81→            output: json!({ "content": hashed_content, "path": path }),
 82→            content: None,
 83→            is_error: false,
 84→        })
 85→    }
 86→}
 87→
 88→// ── WriteFileTool ────────────────────────────────────────────────────
 89→
 90→/// Writes content to a file, overwriting it completely.
 91→pub struct WriteFileTool {
 92→    policy: FsPolicy,
 93→}
 94→
 95→impl WriteFileTool {
 96→    pub fn new(policy: FsPolicy) -> Self {
 97→        Self { policy }
 98→    }
 99→}
100→
101→impl Tool for WriteFileTool {
102→    fn definition(&self) -> ToolDefinition {
103→        ToolDefinition {
104→            name: "write_file".into(),
105→            description: "Writes content to a file, overwriting it completely.".into(),
106→            input_schema: json!({
107→                "type": "object",
108→                "properties": {
109→                    "path": { "type": "string", "description": "Path to the file" },
110→                    "content": { "type": "string", "description": "Content to write" }
111→                },
112→                "required": ["path", "content"]
113→            }),
114→            title: Some("Write File".into()),
115→            output_schema: None,
116→            annotations: Some(ToolAnnotations {
117→                destructive: true,
118→                ..Default::default()
119→            }),
120→            category: Some("filesystem".into()),
121→            tags: vec!["fs".into(), "write".into()],
122→            timeout_secs: Some(30),
123→        }
124→    }
