126→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
127→        let path_str = call
128→            .input
129→            .get("path")
130→            .and_then(|v| v.as_str())
131→            .ok_or_else(|| ToolError::InvalidInput {
132→                message: "Missing or invalid 'path' argument".into(),
133→            })?;
134→
135→        let content = call
136→            .input
137→            .get("content")
138→            .and_then(|v| v.as_str())
139→            .ok_or_else(|| ToolError::InvalidInput {
140→                message: "Missing or invalid 'content' argument".into(),
141→            })?;
142→
143→        let path = self
144→            .policy
145→            .resolve_for_write(Path::new(path_str))
146→            .map_err(|e| ToolError::ExecutionFailed {
147→                tool_name: "write_file".into(),
148→                message: e.to_string(),
149→            })?;
150→
151→        fs::write(&path, content).map_err(|e| ToolError::ExecutionFailed {
152→            tool_name: "write_file".into(),
153→            message: format!("Failed to write file: {e}"),
154→        })?;
155→
156→        Ok(ToolResult {
157→            call_id: call.call_id.clone(),
158→            tool_name: call.tool_name.clone(),
159→            output: json!({ "success": true, "path": path }),
160→            content: None,
161→            is_error: false,
162→        })
163→    }
164→}
