245→// ── GlobTool ─────────────────────────────────────────────────────────
246→
247→/// Searches for files matching a glob pattern within the workspace.
248→pub struct GlobTool {
249→    policy: FsPolicy,
250→}
251→
252→impl GlobTool {
253→    pub fn new(policy: FsPolicy) -> Self {
254→        Self { policy }
255→    }
256→}
257→
258→impl Tool for GlobTool {
259→    fn definition(&self) -> ToolDefinition {
260→        ToolDefinition {
261→            name: "glob".into(),
262→            description: "Search for files matching a glob pattern within the workspace.".into(),
263→            input_schema: json!({
264→                "type": "object",
265→                "properties": {
266→                    "pattern": { "type": "string", "description": "Glob pattern (e.g. **/*.rs)" },
267→                    "path": { "type": "string", "description": "Base directory (optional, defaults to workspace root)" }
268→                },
269→                "required": ["pattern"]
270→            }),
271→            title: Some("Glob Search".into()),
272→            output_schema: None,
273→            annotations: Some(ToolAnnotations {
274→                read_only: true,
275→                idempotent: true,
276→                ..Default::default()
277→            }),
278→            category: Some("filesystem".into()),
279→            tags: vec!["fs".into(), "search".into()],
280→            timeout_secs: Some(30),
281→        }
282→    }
283→
284→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
285→        let pattern = call
286→            .input
287→            .get("pattern")
288→            .and_then(|v| v.as_str())
289→            .ok_or_else(|| ToolError::InvalidInput {
290→                message: "Missing or invalid 'pattern' argument".into(),
291→            })?;
292→
293→        let base_dir = call
294→            .input
295→            .get("path")
296→            .and_then(|v| v.as_str())
297→            .map(PathBuf::from)
298→            .unwrap_or_else(|| self.policy.workspace_root().to_path_buf());
299→
300→        let base_dir = self
301→            .policy
302→            .resolve_existing(Path::new(&base_dir))
303→            .map_err(|e| ToolError::ExecutionFailed {
304→                tool_name: "glob".into(),
305→                message: e.to_string(),
306→            })?;
307→
308→        let full_pattern = base_dir.join(pattern).display().to_string();
309→
310→        let matches: Vec<String> = glob::glob(&full_pattern)
311→            .map_err(|e| ToolError::ExecutionFailed {
312→                tool_name: "glob".into(),
313→                message: format!("Invalid glob pattern: {e}"),
314→            })?
315→            .filter_map(Result::ok)
316→            .filter(|path| self.policy.resolve_existing(path).is_ok())
317→            .map(|path| {
318→                path.strip_prefix(self.policy.workspace_root())
319→                    .map(|p| p.display().to_string())
320→                    .unwrap_or_else(|_| path.display().to_string())
321→            })
322→            .collect();
323→
324→        let count = matches.len();
325→
326→        Ok(ToolResult {
327→            call_id: call.call_id.clone(),
328→            tool_name: call.tool_name.clone(),
329→            output: json!({ "matches": matches, "count": count }),
330→            content: None,
331→            is_error: false,
332→        })
333→    }
334→}
335→
336→// ── GrepTool ─────────────────────────────────────────────────────────
337→
338→/// Searches file contents for a regex pattern within the workspace.
339→pub struct GrepTool {
340→    policy: FsPolicy,
341→}
342→
343→impl GrepTool {
344→    pub fn new(policy: FsPolicy) -> Self {
345→        Self { policy }
346→    }
347→}
348→
349→impl Tool for GrepTool {
350→    fn definition(&self) -> ToolDefinition {
351→        ToolDefinition {
352→            name: "grep".into(),
353→            description: "Search file contents for a regex pattern within the workspace.".into(),
354→            input_schema: json!({
355→                "type": "object",
356→                "properties": {
357→                    "pattern": { "type": "string", "description": "Regex pattern to search for" },
358→                    "path": { "type": "string", "description": "Directory to search (optional, defaults to workspace root)" },
359→                    "glob": { "type": "string", "description": "File glob filter (e.g. *.rs)" },
360→                    "max_matches": { "type": "integer", "description": "Maximum number of matches to return (default 100)" }
361→                },
362→                "required": ["pattern"]
363→            }),
364→            title: Some("Grep Search".into()),
365→            output_schema: None,
366→            annotations: Some(ToolAnnotations {
367→                read_only: true,
368→                idempotent: true,
369→                ..Default::default()
370→            }),
371→            category: Some("filesystem".into()),
372→            tags: vec!["fs".into(), "search".into()],
373→            timeout_secs: Some(60),
374→        }
375→    }
376→
377→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
378→        let pattern_str = call
379→            .input
380→            .get("pattern")
381→            .and_then(|v| v.as_str())
382→            .ok_or_else(|| ToolError::InvalidInput {
383→                message: "Missing or invalid 'pattern' argument".into(),
384→            })?;
385→
386→        let regex = Regex::new(pattern_str).map_err(|e| ToolError::ExecutionFailed {
387→            tool_name: "grep".into(),
388→            message: format!("Invalid regex pattern: {e}"),
389→        })?;
390→
391→        let base_dir = call
392→            .input
393→            .get("path")
394→            .and_then(|v| v.as_str())
395→            .map(PathBuf::from)
396→            .unwrap_or_else(|| self.policy.workspace_root().to_path_buf());
397→
398→        let base_dir = self
399→            .policy
400→            .resolve_existing(Path::new(&base_dir))
401→            .map_err(|e| ToolError::ExecutionFailed {
402→                tool_name: "grep".into(),
403→                message: e.to_string(),
404→            })?;
405→
406→        let glob_filter = call.input.get("glob").and_then(|v| v.as_str());
407→
408→        let max_matches = call
409→            .input
410→            .get("max_matches")
411→            .and_then(serde_json::Value::as_u64)
412→            .unwrap_or(100) as usize;
413→
414→        let mut matches = Vec::new();
415→
416→        for entry in walkdir::WalkDir::new(&base_dir)
417→            .into_iter()
418→            .filter_map(Result::ok)
419→            .filter(|e| e.file_type().is_file())
420→        {
421→            let path = entry.path();
422→
423→            // Apply glob filter if specified
424→            if let Some(glob_pat) = glob_filter {
425→                let file_name = path.file_name().unwrap_or_default().to_string_lossy();
426→                let glob_pattern =
427→                    glob::Pattern::new(glob_pat).map_err(|e| ToolError::ExecutionFailed {
428→                        tool_name: "grep".into(),
429→                        message: format!("Invalid glob filter: {e}"),
430→                    })?;
431→                if !glob_pattern.matches(&file_name) {
432→                    continue;
433→                }
434→            }
435→
436→            // Skip large files (>10MB)
437→            if let Ok(metadata) = path.metadata() {
438→                if metadata.len() > 10 * 1024 * 1024 {
439→                    continue;
440→                }
441→            }
442→
443→            let Ok(file) = fs::File::open(path) else {
444→                continue;
445→            };
446→
447→            let reader = BufReader::new(file);
448→            for (line_no, line) in reader.lines().enumerate() {
449→                let Ok(line) = line else {
450→                    continue;
451→                };
452→
453→                if regex.is_match(&line) {
454→                    let rel_path = path
455→                        .strip_prefix(self.policy.workspace_root())
456→                        .map(|p| p.display().to_string())
457→                        .unwrap_or_else(|_| path.display().to_string());
458→
459→                    matches.push(json!({
460→                        "file": rel_path,
461→                        "line": line_no + 1,
462→                        "text": line
463→                    }));
464→
465→                    if matches.len() >= max_matches {
466→                        break;
467→                    }
468→                }
469→            }
470→
471→            if matches.len() >= max_matches {
472→                break;
473→            }
474→        }
475→
476→        let count = matches.len();
477→
478→        Ok(ToolResult {
479→            call_id: call.call_id.clone(),
480→            tool_name: call.tool_name.clone(),
481→            output: json!({ "matches": matches, "count": count }),
482→            content: None,
483→            is_error: false,
484→        })
485→    }
486→}
