 301→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
 302→    let path = data_dir.join("last_session");
 303→    let raw = std::fs::read_to_string(path).ok()?;
 304→    let session = raw.trim();
 305→    if session.is_empty() {
 306→        None
 307→    } else {
 308→        Some(session.to_owned())
 309→    }
 310→}
 311→
 312→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
 313→    std::fs::create_dir_all(data_dir)?;
 314→    std::fs::write(data_dir.join("last_session"), session)?;
 315→    Ok(())
 316→}
