 617→async fn run_message(
 618→    data_dir: PathBuf,
 619→    resolved: &ResolvedConfig,
 620→    message: String,
 621→    session: Option<String>,
 622→    url: Option<String>,
 623→    json_output: bool,
 624→) -> anyhow::Result<()> {
 625→    // Ensure daemon is running first.
 626→    let base_url = match url {
 627→        Some(u) => u,
 628→        None => {
 629→            daemon::ensure_daemon(
 630→                &data_dir,
 631→                resolved.port,
 632→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 633→                resolved.model.as_deref(),
 634→            )
 635→            .await?
 636→        }
 637→    };
 638→
 639→    // Resolve session via API (no direct journal access).
 640→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 641→
 642→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 643→        tracing::warn!(%error, "failed to persist last_session hint");
 644→    }
 645→
 646→    let exit_code = cli_run::run_cli(
 647→        &base_url,
 648→        &session,
 649→        &message,
 650→        json_output,
 651→        resolved.model.as_deref(),
 652→    )
 653→    .await?;
 654→    if exit_code != 0 {
 655→        std::process::exit(exit_code);
 656→    }
 657→    Ok(())
 658→}
