 661→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 662→    match action {
 663→        ConfigAction::Init => {
 664→            let path = config::local_config_path(data_dir);
 665→            if path.exists() {
 666→                println!("Config file already exists: {}", path.display());
 667→            } else {
 668→                std::fs::create_dir_all(data_dir)?;
 669→                std::fs::write(&path, config::default_config_content())?;
 670→                println!("Created config: {}", path.display());
 671→            }
 672→        }
 673→        ConfigAction::Set { key, value } => {
 674→            let mut cfg = config::load_config(data_dir);
 675→            cfg.set_key(&key, &value)
 676→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 677→            config::save_config(data_dir, &cfg)?;
 678→            println!("{key} = {value}");
 679→        }
 680→        ConfigAction::Get { key } => {
 681→            let cfg = config::load_config(data_dir);
 682→            match cfg.get_key(&key) {
 683→                Some(value) => println!("{value}"),
 684→                None => println!("(not set)"),
 685→            }
 686→        }
 687→        ConfigAction::List => {
 688→            let cfg = config::load_config(data_dir);
 689→            let content = toml::to_string_pretty(&cfg)
 690→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 691→            if content.trim().is_empty()
 692→                || content.trim() == "[defaults]\n\n[agent]"
 693→                || content
 694→                    .lines()
 695→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 696→            {
 697→                println!("(no config values set)");
 698→                if let Some(path) = config::global_config_path() {
 699→                    println!("Global config: {}", path.display());
 700→                }
 701→                println!(
 702→                    "Local config:  {}",
 703→                    config::local_config_path(data_dir).display()
 704→                );
 705→            } else {
 706→                print!("{content}");
 707→            }
 708→        }
 709→    }
 710→    Ok(())
 711→}
