  1→use std::fs;
  2→use std::path::{Path, PathBuf};
  3→
  4→use lago_core::{BlobHash, LagoError, LagoResult};
  5→use tracing::{debug, trace};
  6→
  7→use crate::compress;
  8→use crate::hash;
  9→
 10→/// Content-addressed blob store backed by the local filesystem.
 11→///
 12→/// Blobs are stored compressed (zstd) under a git-like object layout:
 13→/// `{root}/{first-2-chars}/{remaining-hash}.zst`
 14→///
 15→/// Deduplication is automatic — writing the same content twice is a no-op
 16→/// because the content hash determines the storage path.
 17→pub struct BlobStore {
 18→    root: PathBuf,
 19→}
 20→
 21→impl BlobStore {
 22→    /// Open (or create) a blob store rooted at the given directory.
 23→    pub fn open(path: impl AsRef<Path>) -> LagoResult<Self> {
 24→        let root = path.as_ref().to_path_buf();
 25→        fs::create_dir_all(&root)?;
 26→        debug!(path = %root.display(), "blob store opened");
 27→        Ok(Self { root })
 28→    }
 29→
 30→    /// Store data and return its content hash.
 31→    ///
 32→    /// If a blob with the same hash already exists on disk, the write is
 33→    /// skipped (content-addressed deduplication).
 34→    pub fn put(&self, data: &[u8]) -> LagoResult<BlobHash> {
 35→        let hash = hash::hash_bytes(data);
 36→
 37→        if self.exists(&hash) {
 38→            trace!(hash = %hash, "blob already exists, skipping write");
 39→            return Ok(hash);
 40→        }
 41→
 42→        let blob_path = self.blob_path(&hash);
 43→
 44→        // Ensure the shard directory exists
 45→        if let Some(parent) = blob_path.parent() {
 46→            fs::create_dir_all(parent)?;
 47→        }
 48→
 49→        let compressed = compress::compress(data)?;
 50→
 51→        // Write atomically via a temp file to avoid partial writes on crash
 52→        let tmp_path = blob_path.with_extension("zst.tmp");
 53→        fs::write(&tmp_path, &compressed)?;
 54→        fs::rename(&tmp_path, &blob_path)?;
 55→
 56→        debug!(hash = %hash, size = data.len(), compressed = compressed.len(), "blob stored");
 57→        Ok(hash)
 58→    }
 59→
 60→    /// Retrieve the decompressed contents of a blob by its hash.
 61→    pub fn get(&self, hash: &BlobHash) -> LagoResult<Vec<u8>> {
 62→        let blob_path = self.blob_path(hash);
 63→
 64→        if !blob_path.exists() {
 65→            return Err(LagoError::BlobNotFound(hash.to_string()));
 66→        }
 67→
 68→        let compressed = fs::read(&blob_path)?;
 69→        let data = compress::decompress(&compressed)?;
 70→
 71→        trace!(hash = %hash, size = data.len(), "blob retrieved");
 72→        Ok(data)
 73→    }
 74→
 75→    /// Check whether a blob with the given hash exists on disk.
 76→    pub fn exists(&self, hash: &BlobHash) -> bool {
 77→        self.blob_path(hash).exists()
 78→    }
 79→
 80→    /// Delete a blob from disk. Returns an error if the blob does not exist.
 81→    pub fn delete(&self, hash: &BlobHash) -> LagoResult<()> {
 82→        let blob_path = self.blob_path(hash);
 83→
 84→        if !blob_path.exists() {
 85→            return Err(LagoError::BlobNotFound(hash.to_string()));
 86→        }
 87→
 88→        fs::remove_file(&blob_path)?;
 89→        debug!(hash = %hash, "blob deleted");
 90→
 91→        // Try to remove the shard directory if empty (best-effort)
 92→        if let Some(parent) = blob_path.parent() {
 93→            let _ = fs::remove_dir(parent);
 94→        }
 95→
 96→        Ok(())
 97→    }
 98→
 99→    // ---
100→    // Internal helpers
101→
102→    /// Compute the on-disk path for a given blob hash.
103→    ///
104→    /// Layout: `{root}/{hash[0..2]}/{hash[2..]}.zst`
105→    fn blob_path(&self, hash: &BlobHash) -> PathBuf {
106→        let hex = hash.as_str();
107→        let (prefix, rest) = hex.split_at(2);
108→        self.root.join(prefix).join(format!("{rest}.zst"))
109→    }
110→}
