    port: Option<u16>,

    /// Serve console assets from a local directory (dev mode)
    #[arg(long, global = true)]
    console_dir: Option<PathBuf>,

    /// LLM provider (anthropic, openai, ollama, mock)
    #[arg(long, global = true)]
    provider: Option<String>,

    /// Model name override
