 252→/// Build provider from resolved configuration.
 253→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
 254→    let pc = resolved.provider_config.as_ref();
 255→
 256→    match resolved.provider.as_str() {
 257→        "mock" => {
 258→            tracing::warn!("Provider: MockProvider (forced via config)");
 259→            Ok(Arc::new(MockProvider))
 260→        }
 261→        "openai" | "codex" | "openai-codex" => {
 262→            // Try OAuth credential first, then fall back to env var / resolved config.
 263→            if let Some(p) = try_openai_oauth_provider() {
 264→                return Ok(p);
 265→            }
 266→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
 267→                resolved.model.as_deref(),
 268→                pc.and_then(|p| p.base_url.as_deref()),
 269→                pc.and_then(|p| p.max_tokens),
 270→            )?;
 271→            tracing::info!(model = %config.model, "Provider: OpenAI");
 272→            Ok(Arc::new(
 273→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 274→            ))
 275→        }
 276→        "ollama" => {
 277→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
 278→                resolved.model.as_deref(),
 279→                pc.and_then(|p| p.base_url.as_deref()),
 280→                pc.and_then(|p| p.max_tokens),
 281→                pc.and_then(|p| p.enable_streaming),
 282→            )?;
 283→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 284→            Ok(Arc::new(
 285→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 286→            ))
 287→        }
 288→        "anthropic" => {
 289→            let config = AnthropicConfig::from_resolved(
 290→                resolved.model.as_deref(),
 291→                pc.and_then(|p| p.base_url.as_deref()),
 292→                pc.and_then(|p| p.max_tokens),
 293→            )?;
 294→            tracing::info!(model = %config.model, "Provider: Anthropic");
 295→            Ok(Arc::new(AnthropicProvider::new(config)))
 296→        }
 297→        // Auto-detect: try providers in order
 298→        _ => {
 299→            if let Ok(config) = AnthropicConfig::from_env() {
 300→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 301→                Ok(Arc::new(AnthropicProvider::new(config)))
 302→            } else if let Some(p) = try_openai_oauth_provider() {
 303→                Ok(p)
 304→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
 305→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
 306→                Ok(Arc::new(
 307→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 308→                ))
 309→            } else {
 310→                tracing::warn!(
 311→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
 312→                );
 313→                Ok(Arc::new(MockProvider))
 314→            }
 315→        }
 316→    }
 317→}
