 494→async fn run_chat(
 495→    data_dir: PathBuf,
 496→    resolved: &ResolvedConfig,
 497→    session: Option<String>,
 498→    url: Option<String>,
 499→) -> anyhow::Result<()> {
 500→    // Ensure daemon is running first to avoid redb lock conflicts.
 501→    let base_url = match url {
 502→        Some(u) => u,
 503→        None => {
 504→            daemon::ensure_daemon(
 505→                &data_dir,
 506→                resolved.port,
 507→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 508→                resolved.model.as_deref(),
 509→            )
 510→            .await?
 511→        }
 512→    };
 513→
 514→    // Resolve session via API (no direct journal access).
 515→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 516→    tracing::info!(session = %session, "launching TUI");
 517→
 518→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 519→        tracing::warn!(%error, "failed to persist last_session hint");
 520→    }
 521→
 522→    arcan_tui::run_tui(base_url, session).await
 523→}
