 774→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 775→    // Normalize provider name for credential lookup.
 776→    let normalized = match provider {
 777→        "codex" | "openai-codex" => "openai",
 778→        other => other,
 779→    };
 780→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
