  1→use std::fs;
  2→use std::path::Path;
  3→use std::time::Duration;
  4→
  5→/// Check whether a daemon is already healthy at the given URL.
  6→async fn is_daemon_healthy(base_url: &str) -> bool {
  7→    daemon_health(base_url).await.is_some()
  8→}
  9→
 10→/// Probe the daemon's `/health` endpoint.
 11→/// Returns the reported version string on success, or `None` if unreachable.
 12→async fn daemon_health(base_url: &str) -> Option<String> {
 13→    let url = format!("{base_url}/health");
 14→    let client = reqwest::Client::builder()
 15→        .timeout(Duration::from_secs(2))
 16→        .build()
 17→        .ok()?;
 18→    let resp = client.get(&url).send().await.ok()?;
 19→    if !resp.status().is_success() {
 20→        return None;
 21→    }
 22→    let body: serde_json::Value = resp.json().await.ok()?;
 23→    // Old daemons without a version field return None here — treated as outdated.
 24→    body.get("version")
 25→        .and_then(serde_json::Value::as_str)
 26→        .map(str::to_string)
 27→}
 28→
 29→/// Check if a PID file exists and the process is alive.
 30→/// Returns `Some(pid)` if alive, `None` if dead or no PID file.
 31→pub fn check_existing_pid(data_dir: &Path) -> Option<u32> {
 32→    let pid_path = data_dir.join("daemon.pid");
 33→    let raw = fs::read_to_string(&pid_path).ok()?;
 34→    let pid: u32 = raw.trim().parse().ok()?;
 35→
 36→    if is_process_alive(pid) {
 37→        Some(pid)
 38→    } else {
 39→        tracing::warn!(pid, "Stale daemon.pid found (process dead), removing");
 40→        let _ = fs::remove_file(&pid_path);
 41→        None
 42→    }
 43→}
 44→
 45→/// Check if a process with the given PID is alive using `kill -0`.
 46→#[cfg(unix)]
 47→pub fn is_process_alive(pid: u32) -> bool {
 48→    std::process::Command::new("kill")
 49→        .args(["-0", &pid.to_string()])
 50→        .stdout(std::process::Stdio::null())
 51→        .stderr(std::process::Stdio::null())
 52→        .status()
 53→        .is_ok_and(|s| s.success())
 54→}
 55→
 56→#[cfg(not(unix))]
 57→pub fn is_process_alive(_pid: u32) -> bool {
 58→    // On non-Unix, we can't cheaply check — assume alive if PID file exists.
 59→    true
 60→}
 61→
 62→/// Remove the daemon.pid file (called on graceful shutdown).
 63→pub fn remove_pid_file(data_dir: &Path) {
 64→    let pid_path = data_dir.join("daemon.pid");
 65→    if pid_path.exists() {
 66→        let _ = fs::remove_file(&pid_path);
 67→        tracing::info!("Removed daemon.pid");
 68→    }
 69→}
