 71→/// Stop a running daemon by sending SIGTERM and waiting for exit.
 72→pub async fn stop_daemon(data_dir: &Path, port: u16) -> anyhow::Result<()> {
 73→    let base_url = format!("http://127.0.0.1:{port}");
 74→
 75→    // Check PID file first.
 76→    let Some(pid) = check_existing_pid(data_dir) else {
 77→        // No live process — check if the port is healthy anyway.
 78→        if is_daemon_healthy(&base_url).await {
 79→            anyhow::bail!(
 80→                "Daemon is healthy on {base_url} but no PID file found. Stop it manually."
 81→            );
 82→        }
 83→        anyhow::bail!("No running daemon found.");
 84→    };
 85→
 86→    // Send SIGTERM.
 87→    #[cfg(unix)]
 88→    {
 89→        let status = std::process::Command::new("kill")
 90→            .args([&pid.to_string()])
 91→            .stdout(std::process::Stdio::null())
 92→            .stderr(std::process::Stdio::null())
 93→            .status();
 94→        if status.is_err() || !status.unwrap().success() {
 95→            anyhow::bail!("Failed to send SIGTERM to PID {pid}");
 96→        }
 97→    }
 98→
 99→    #[cfg(not(unix))]
100→    {
101→        anyhow::bail!("stop is only supported on Unix systems");
102→    }
103→
104→    // Poll until process is dead (up to 10s).
105→    for _ in 0..50 {
106→        tokio::time::sleep(Duration::from_millis(200)).await;
107→        if !is_process_alive(pid) {
108→            remove_pid_file(data_dir);
109→            return Ok(());
110→        }
111→    }
112→
113→    anyhow::bail!("Daemon (PID {pid}) did not exit within 10 seconds");
114→}
