116→/// Ensure a daemon is running on the given port with a matching version.
117→///
118→/// 1. Probe `GET /health`. If healthy **and** version matches, return immediately.
119→/// 2. If healthy but version mismatches, stop the old daemon and respawn.
120→/// 3. Check `daemon.pid` — if process alive but health fails, wait briefly.
121→/// 4. If PID is stale, remove PID file and proceed.
122→/// 5. Spawn `arcan serve` as a detached child process.
123→/// 6. Poll `/health` until it succeeds (up to ~12 s).
124→pub async fn ensure_daemon(
125→    data_dir: &Path,
126→    port: u16,
127→    provider: Option<&str>,
128→    model: Option<&str>,
129→) -> anyhow::Result<String> {
130→    let base_url = format!("http://127.0.0.1:{port}");
131→    let current_version = env!("CARGO_PKG_VERSION");
132→
133→    if let Some(daemon_version) = daemon_health(&base_url).await {
134→        if daemon_version == current_version {
135→            tracing::info!("Daemon already running on {base_url} (v{daemon_version})");
136→            return Ok(base_url);
137→        }
138→        // Version mismatch — restart the daemon.
139→        tracing::warn!(
140→            daemon_version,
141→            current_version,
142→            "Daemon version mismatch, restarting"
143→        );
144→        if let Err(e) = stop_daemon(data_dir, port).await {
145→            tracing::warn!("Failed to stop outdated daemon: {e}, spawning anyway");
146→        }
147→    } else if is_daemon_healthy(&base_url).await {
148→        // Healthy but no version field — old daemon without version support.
149→        tracing::warn!("Daemon running without version info, restarting");
150→        if let Err(e) = stop_daemon(data_dir, port).await {
151→            tracing::warn!("Failed to stop old daemon: {e}, spawning anyway");
152→        }
153→    }
154→
155→    // Check PID file before spawning a new daemon.
156→    if let Some(pid) = check_existing_pid(data_dir) {
157→        // Process is alive but health check failed — it might be starting up.
158→        tracing::info!(pid, "Daemon process alive, waiting for health...");
159→        let delay = Duration::from_millis(200);
160→        for _ in 0..15 {
161→            tokio::time::sleep(delay).await;
162→            if let Some(v) = daemon_health(&base_url).await {
163→                if v == current_version {
164→                    tracing::info!("Existing daemon became healthy on {base_url} (v{v})");
165→                    return Ok(base_url);
166→                }
167→            }
168→        }
169→        // Still not healthy after 3s — the process might be stuck.
170→        tracing::warn!(
171→            pid,
172→            "Daemon process alive but not healthy/current after 3s, spawning new"
173→        );
174→    }
175→
176→    tracing::info!("Starting daemon on port {port}...");
177→
178→    fs::create_dir_all(data_dir)?;
179→    let log_file = fs::File::create(data_dir.join("daemon.log"))?;
180→    let stderr_log = log_file.try_clone()?;
181→
182→    // Resolve the current executable so `arcan serve` uses the same binary.
183→    let exe = std::env::current_exe()?;
184→
185→    let port_str = port.to_string();
186→    let dir_str = data_dir.to_string_lossy().to_string();
187→    let mut args = vec!["serve", "--port", &port_str, "--data-dir", &dir_str];
188→    if let Some(p) = provider {
189→        args.extend(["--provider", p]);
190→    }
191→    if let Some(m) = model {
192→        args.extend(["--model", m]);
193→    }
194→
195→    let child = std::process::Command::new(exe)
196→        .args(&args)
197→        .stdout(log_file)
198→        .stderr(stderr_log)
199→        .stdin(std::process::Stdio::null())
200→        .spawn()?;
201→
202→    // Write PID for later inspection / cleanup.
203→    fs::write(data_dir.join("daemon.pid"), child.id().to_string())?;
204→
205→    // Poll health endpoint.
206→    let max_retries = 60;
207→    let delay = Duration::from_millis(200);
208→    for i in 0..max_retries {
209→        tokio::time::sleep(delay).await;
210→        if is_daemon_healthy(&base_url).await {
211→            tracing::info!("Daemon healthy after {} ms", (i + 1) * 200);
212→            return Ok(base_url);
213→        }
214→    }
215→
216→    anyhow::bail!(
217→        "Daemon failed to become healthy within {}s. Check {}/daemon.log for details.",
218→        max_retries * 200 / 1000,
219→        data_dir.display()
220→    );
221→}
