  1→//! Persistent CLI configuration with layered resolution.
  2→//!
  3→//! Resolution order: hardcoded defaults → global config → project-local config → env vars → CLI flags.
  4→
  5→use serde::{Deserialize, Serialize};
  6→use std::collections::HashMap;
  7→use std::path::{Path, PathBuf};
  8→
  9→/// Top-level TOML configuration file structure.
 10→///
 11→/// All fields use `Option<T>` to allow partial configs and clean merging.
 12→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 13→#[serde(default)]
 14→pub struct ArcanConfig {
 15→    pub defaults: DefaultsConfig,
 16→    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
 17→    pub providers: HashMap<String, ProviderConfig>,
 18→    pub agent: AgentConfig,
 19→}
 20→
 21→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 22→#[serde(default)]
 23→pub struct DefaultsConfig {
 24→    pub provider: Option<String>,
 25→    pub model: Option<String>,
 26→    pub port: Option<u16>,
 27→    pub autonomic_url: Option<String>,
 28→}
 29→
 30→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 31→#[serde(default)]
 32→pub struct ProviderConfig {
 33→    pub model: Option<String>,
 34→    pub base_url: Option<String>,
 35→    pub max_tokens: Option<u32>,
 36→    pub enable_streaming: Option<bool>,
 37→}
 38→
 39→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 40→#[serde(default)]
 41→pub struct AgentConfig {
 42→    pub max_iterations: Option<u32>,
 43→    pub approval_timeout: Option<u64>,
 44→}
 45→
 46→/// Fully resolved configuration with concrete values (no Options).
 47→#[derive(Debug, Clone)]
 48→#[allow(dead_code)]
 49→pub struct ResolvedConfig {
 50→    pub provider: String,
 51→    pub model: Option<String>,
 52→    pub port: u16,
 53→    pub max_iterations: u32,
 54→    pub approval_timeout: u64,
 55→    pub provider_config: Option<ProviderConfig>,
 56→    pub autonomic_url: Option<String>,
 57→}
 58→
 59→impl ArcanConfig {
 60→    /// Merge `other` on top of `self`. Non-None values in `other` win.
 61→    pub fn merge(&mut self, other: &ArcanConfig) {
 62→        if other.defaults.provider.is_some() {
 63→            self.defaults.provider.clone_from(&other.defaults.provider);
 64→        }
 65→        if other.defaults.model.is_some() {
 66→            self.defaults.model.clone_from(&other.defaults.model);
 67→        }
 68→        if other.defaults.port.is_some() {
 69→            self.defaults.port = other.defaults.port;
 70→        }
 71→        if other.defaults.autonomic_url.is_some() {
 72→            self.defaults
 73→                .autonomic_url
 74→                .clone_from(&other.defaults.autonomic_url);
 75→        }
 76→        if other.agent.max_iterations.is_some() {
 77→            self.agent.max_iterations = other.agent.max_iterations;
 78→        }
 79→        if other.agent.approval_timeout.is_some() {
 80→            self.agent.approval_timeout = other.agent.approval_timeout;
 81→        }
 82→        for (name, pc) in &other.providers {
 83→            let entry = self.providers.entry(name.clone()).or_default();
 84→            if pc.model.is_some() {
 85→                entry.model.clone_from(&pc.model);
 86→            }
 87→            if pc.base_url.is_some() {
 88→                entry.base_url.clone_from(&pc.base_url);
 89→            }
 90→            if pc.max_tokens.is_some() {
 91→                entry.max_tokens = pc.max_tokens;
 92→            }
 93→            if pc.enable_streaming.is_some() {
 94→                entry.enable_streaming = pc.enable_streaming;
 95→            }
 96→        }
 97→    }
 98→
 99→    /// Set a key using dotted notation. Shortcut keys:
100→    /// `provider` → `defaults.provider`, `model` → `defaults.model`, `port` → `defaults.port`.
101→    pub fn set_key(&mut self, key: &str, value: &str) -> Result<(), String> {
102→        match key {
103→            "provider" | "defaults.provider" => {
104→                self.defaults.provider = Some(value.to_owned());
105→            }
106→            "model" | "defaults.model" => {
107→                self.defaults.model = Some(value.to_owned());
108→            }
109→            "port" | "defaults.port" => {
110→                let port: u16 = value
111→                    .parse()
112→                    .map_err(|e| format!("invalid port value: {e}"))?;
113→                self.defaults.port = Some(port);
114→            }
115→            "autonomic_url" | "defaults.autonomic_url" => {
116→                self.defaults.autonomic_url = Some(value.to_owned());
117→            }
118→            "agent.max_iterations" | "max_iterations" => {
119→                let v: u32 = value
120→                    .parse()
121→                    .map_err(|e| format!("invalid max_iterations: {e}"))?;
122→                self.agent.max_iterations = Some(v);
123→            }
124→            "agent.approval_timeout" | "approval_timeout" => {
125→                let v: u64 = value
126→                    .parse()
127→                    .map_err(|e| format!("invalid approval_timeout: {e}"))?;
128→                self.agent.approval_timeout = Some(v);
129→            }
130→            _ if key.starts_with("providers.") => {
131→                // e.g. providers.ollama.base_url
132→                let rest = &key["providers.".len()..];
133→                let parts: Vec<&str> = rest.splitn(2, '.').collect();
134→                if parts.len() != 2 {
135→                    return Err(format!(
136→                        "invalid provider key: {key} (expected providers.<name>.<field>)"
137→                    ));
138→                }
139→                let provider_name = parts[0];
140→                let field = parts[1];
141→                let entry = self.providers.entry(provider_name.to_owned()).or_default();
142→                match field {
143→                    "model" => entry.model = Some(value.to_owned()),
144→                    "base_url" => entry.base_url = Some(value.to_owned()),
145→                    "max_tokens" => {
146→                        let v: u32 = value
147→                            .parse()
148→                            .map_err(|e| format!("invalid max_tokens: {e}"))?;
149→                        entry.max_tokens = Some(v);
150→                    }
151→                    "enable_streaming" => {
152→                        let v: bool = value
153→                            .parse()
154→                            .map_err(|e| format!("invalid enable_streaming: {e}"))?;
155→                        entry.enable_streaming = Some(v);
156→                    }
157→                    _ => return Err(format!("unknown provider field: {field}")),
158→                }
159→            }
160→            _ => return Err(format!("unknown config key: {key}")),
161→        }
162→        Ok(())
163→    }
164→
165→    /// Get a value by key. Returns None if unset.
166→    pub fn get_key(&self, key: &str) -> Option<String> {
167→        match key {
168→            "provider" | "defaults.provider" => self.defaults.provider.clone(),
169→            "model" | "defaults.model" => self.defaults.model.clone(),
170→            "port" | "defaults.port" => self.defaults.port.map(|p| p.to_string()),
171→            "autonomic_url" | "defaults.autonomic_url" => self.defaults.autonomic_url.clone(),
172→            "agent.max_iterations" | "max_iterations" => {
173→                self.agent.max_iterations.map(|v| v.to_string())
174→            }
175→            "agent.approval_timeout" | "approval_timeout" => {
176→                self.agent.approval_timeout.map(|v| v.to_string())
177→            }
178→            _ if key.starts_with("providers.") => {
179→                let rest = &key["providers.".len()..];
180→                let parts: Vec<&str> = rest.splitn(2, '.').collect();
181→                if parts.len() != 2 {
182→                    return None;
183→                }
184→                let pc = self.providers.get(parts[0])?;
185→                match parts[1] {
186→                    "model" => pc.model.clone(),
187→                    "base_url" => pc.base_url.clone(),
188→                    "max_tokens" => pc.max_tokens.map(|v| v.to_string()),
189→                    "enable_streaming" => pc.enable_streaming.map(|v| v.to_string()),
190→                    _ => None,
191→                }
192→            }
193→            _ => None,
194→        }
195→    }
196→}
197→
198→/// Global config path: `~/.config/arcan/config.toml`
199→pub fn global_config_path() -> Option<PathBuf> {
200→    dirs::config_dir().map(|d| d.join("arcan").join("config.toml"))
201→}
202→
203→/// Project-local config path: `<data_dir>/config.toml`
204→pub fn local_config_path(data_dir: &Path) -> PathBuf {
205→    data_dir.join("config.toml")
206→}
207→
208→/// Load and merge config from global + local files.
209→pub fn load_config(data_dir: &Path) -> ArcanConfig {
210→    let mut config = ArcanConfig::default();
211→
212→    // Layer 1: global config
213→    if let Some(global_path) = global_config_path() {
214→        if let Some(global) = load_config_file(&global_path) {
215→            config.merge(&global);
216→        }
217→    }
218→
219→    // Layer 2: project-local config
220→    let local_path = local_config_path(data_dir);
221→    if let Some(local) = load_config_file(&local_path) {
222→        config.merge(&local);
223→    }
224→
225→    config
226→}
227→
228→/// Load a single TOML config file. Returns None if file doesn't exist or is invalid.
229→fn load_config_file(path: &Path) -> Option<ArcanConfig> {
230→    let content = std::fs::read_to_string(path).ok()?;
231→    toml::from_str(&content).ok()
232→}
233→
234→/// Save config to the project-local config file.
235→pub fn save_config(data_dir: &Path, config: &ArcanConfig) -> anyhow::Result<()> {
236→    let path = local_config_path(data_dir);
237→    std::fs::create_dir_all(data_dir)?;
238→    let content = toml::to_string_pretty(config)
239→        .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
240→    std::fs::write(&path, content)?;
241→    Ok(())
242→}
243→
244→/// Resolve the final config by applying env vars and CLI overrides on top.
245→pub fn resolve(
246→    config: &ArcanConfig,
247→    cli_provider: Option<&str>,
248→    cli_model: Option<&str>,
249→    cli_port: Option<u16>,
250→    cli_max_iterations: Option<u32>,
251→    cli_approval_timeout: Option<u64>,
252→    cli_autonomic_url: Option<&str>,
253→) -> ResolvedConfig {
254→    // Provider: CLI > env > config > ""
255→    let provider = cli_provider
256→        .map(String::from)
257→        .or_else(|| std::env::var("ARCAN_PROVIDER").ok())
258→        .or_else(|| config.defaults.provider.clone())
259→        .unwrap_or_default();
260→
261→    // Model: CLI > env > provider-specific config > defaults config > None
262→    let model = cli_model
263→        .map(String::from)
264→        .or_else(|| std::env::var("ARCAN_MODEL").ok())
265→        .or_else(|| {
266→            config
267→                .providers
268→                .get(&provider)
269→                .and_then(|pc| pc.model.clone())
270→        })
271→        .or_else(|| config.defaults.model.clone());
272→
273→    // Port: CLI > env > config > 3000
274→    let port = cli_port
275→        .or_else(|| {
276→            std::env::var("ARCAN_PORT")
277→                .ok()
278→                .and_then(|s| s.parse().ok())
279→        })
280→        .or(config.defaults.port)
281→        .unwrap_or(3000);
282→
283→    // Max iterations: CLI > config > 10
284→    let max_iterations = cli_max_iterations
285→        .or(config.agent.max_iterations)
286→        .unwrap_or(10);
287→
288→    // Approval timeout: CLI > config > 300
289→    let approval_timeout = cli_approval_timeout
290→        .or(config.agent.approval_timeout)
291→        .unwrap_or(300);
292→
293→    // Autonomic URL: CLI > env > config > None
294→    let autonomic_url = cli_autonomic_url
295→        .map(String::from)
296→        .or_else(|| std::env::var("ARCAN_AUTONOMIC_URL").ok())
297→        .or_else(|| config.defaults.autonomic_url.clone());
298→
299→    // Provider-specific config section
300→    let provider_config = config.providers.get(&provider).cloned();
301→
302→    ResolvedConfig {
303→        provider,
304→        model,
305→        port,
306→        max_iterations,
307→        approval_timeout,
308→        provider_config,
309→        autonomic_url,
310→    }
311→}
