  1→//! Bridge adapter: wraps any `aios_protocol::tool::Tool` as an `arcan_core::runtime::Tool`.
  2→//!
  3→//! This lets Praxis canonical tools (which implement the aiOS `Tool` trait) be
  4→//! registered in Arcan's `ToolRegistry` without modifying either side.
  5→
  6→use arcan_core::error::CoreError;
  7→use arcan_core::protocol as arcan_proto;
  8→use arcan_core::runtime as arcan_rt;
  9→
 10→use aios_protocol::tool as proto_tool;
 11→
 12→/// Adapter that wraps an `aios_protocol::tool::Tool` impl so it satisfies
 13→/// `arcan_core::runtime::Tool`.
 14→pub struct PraxisToolBridge<T> {
 15→    inner: T,
 16→}
 17→
 18→impl<T> PraxisToolBridge<T> {
 19→    pub fn new(inner: T) -> Self {
 20→        Self { inner }
 21→    }
 22→}
 23→
 24→// ── Type conversion helpers ──────────────────────────────────────────
 25→
 26→fn proto_def_to_arcan(def: proto_tool::ToolDefinition) -> arcan_proto::ToolDefinition {
 27→    arcan_proto::ToolDefinition {
 28→        name: def.name,
 29→        description: def.description,
 30→        input_schema: def.input_schema,
 31→        title: def.title,
 32→        output_schema: def.output_schema,
 33→        annotations: def.annotations.map(|a| arcan_proto::ToolAnnotations {
 34→            read_only: a.read_only,
 35→            destructive: a.destructive,
 36→            idempotent: a.idempotent,
 37→            open_world: a.open_world,
 38→            requires_confirmation: a.requires_confirmation,
 39→        }),
 40→        category: def.category,
 41→        tags: def.tags,
 42→        timeout_secs: def.timeout_secs,
 43→    }
 44→}
 45→
 46→fn arcan_call_to_proto(call: &arcan_proto::ToolCall) -> proto_tool::ToolCall {
 47→    proto_tool::ToolCall {
 48→        call_id: call.call_id.clone(),
 49→        tool_name: call.tool_name.clone(),
 50→        input: call.input.clone(),
 51→        requested_capabilities: Vec::new(),
 52→    }
 53→}
 54→
 55→fn arcan_ctx_to_proto(ctx: &arcan_rt::ToolContext) -> proto_tool::ToolContext {
 56→    proto_tool::ToolContext {
 57→        run_id: ctx.run_id.clone(),
 58→        session_id: ctx.session_id.clone(),
 59→        iteration: ctx.iteration,
 60→    }
 61→}
 62→
 63→fn proto_result_to_arcan(result: proto_tool::ToolResult) -> arcan_proto::ToolResult {
 64→    arcan_proto::ToolResult {
 65→        call_id: result.call_id,
 66→        tool_name: result.tool_name,
 67→        output: result.output,
 68→        content: result.content.map(|blocks| {
 69→            blocks
 70→                .into_iter()
 71→                .map(|c| match c {
 72→                    proto_tool::ToolContent::Text { text } => {
 73→                        arcan_proto::ToolContent::Text { text }
 74→                    }
 75→                    proto_tool::ToolContent::Image { data, mime_type } => {
 76→                        arcan_proto::ToolContent::Image { data, mime_type }
 77→                    }
 78→                    proto_tool::ToolContent::Json { value } => {
 79→                        arcan_proto::ToolContent::Json { value }
 80→                    }
 81→                })
 82→                .collect()
 83→        }),
 84→        is_error: result.is_error,
 85→        state_patch: None,
 86→    }
 87→}
 88→
 89→fn proto_err_to_core(err: proto_tool::ToolError) -> CoreError {
 90→    match err {
 91→        proto_tool::ToolError::NotFound { tool_name } => CoreError::ToolNotFound { tool_name },
 92→        proto_tool::ToolError::ExecutionFailed { tool_name, message } => {
 93→            CoreError::ToolExecution { tool_name, message }
 94→        }
 95→        other => CoreError::ToolExecution {
 96→            tool_name: String::new(),
 97→            message: other.to_string(),
 98→        },
 99→    }
100→}
101→
102→// ── Trait impl ───────────────────────────────────────────────────────
103→
104→impl<T: proto_tool::Tool + Send + Sync> arcan_rt::Tool for PraxisToolBridge<T> {
105→    fn definition(&self) -> arcan_proto::ToolDefinition {
106→        proto_def_to_arcan(self.inner.definition())
107→    }
108→
109→    fn execute(
110→        &self,
111→        call: &arcan_proto::ToolCall,
112→        ctx: &arcan_rt::ToolContext,
113→    ) -> Result<arcan_proto::ToolResult, CoreError> {
114→        let proto_call = arcan_call_to_proto(call);
115→        let proto_ctx = arcan_ctx_to_proto(ctx);
116→
117→        self.inner
118→            .execute(&proto_call, &proto_ctx)
119→            .map(proto_result_to_arcan)
120→            .map_err(proto_err_to_core)
121→    }
122→}
