  1→//! Lago-backed tracked filesystem: intercepts writes for O(1) event emission.
  2→//!
  3→//! [`LagoTrackedFs`] implements [`FsPort`] by delegating all reads to
  4→//! a [`LocalFs`] and intercepting writes to produce `EventPayload::FileWrite`
  5→//! events via a [`FsTracker`]. Events are sent through an mpsc channel
  6→//! to a background writer that persists them to the Lago journal.
  7→
  8→use lago_core::event::EventPayload;
  9→use lago_core::{BranchId, EventEnvelope, EventId, Journal, SessionId};
 10→use lago_fs::FsTracker;
 11→use praxis_core::error::PraxisResult;
 12→use praxis_core::fs_port::{FsDirEntry, FsMetadata, FsPort};
 13→use praxis_core::local_fs::LocalFs;
 14→use std::path::{Path, PathBuf};
 15→use std::sync::Arc;
 16→use tokio::sync::mpsc;
 17→
 18→/// Filesystem implementation that tracks writes via Lago's [`FsTracker`].
 19→///
 20→/// All read operations delegate to the underlying [`LocalFs`].
 21→/// Write operations first write to disk, then notify the tracker
 22→/// which produces an `EventPayload` sent through the channel.
 23→pub struct LagoTrackedFs {
 24→    local_fs: LocalFs,
 25→    tracker: Arc<FsTracker>,
 26→    tx: mpsc::Sender<EventPayload>,
 27→}
 28→
 29→impl LagoTrackedFs {
 30→    /// Create a new tracked filesystem.
 31→    pub fn new(local_fs: LocalFs, tracker: Arc<FsTracker>, tx: mpsc::Sender<EventPayload>) -> Self {
 32→        Self {
 33→            local_fs,
 34→            tracker,
 35→            tx,
 36→        }
 37→    }
 38→}
 39→
 40→impl FsPort for LagoTrackedFs {
 41→    fn workspace_root(&self) -> &Path {
 42→        self.local_fs.workspace_root()
 43→    }
 44→
 45→    fn resolve(&self, path: &Path) -> PraxisResult<PathBuf> {
 46→        self.local_fs.resolve(path)
 47→    }
 48→
 49→    fn resolve_for_write(&self, path: &Path) -> PraxisResult<PathBuf> {
 50→        self.local_fs.resolve_for_write(path)
 51→    }
 52→
 53→    fn read_to_string(&self, path: &Path) -> PraxisResult<String> {
 54→        self.local_fs.read_to_string(path)
 55→    }
 56→
 57→    fn read_bytes(&self, path: &Path) -> PraxisResult<Vec<u8>> {
 58→        self.local_fs.read_bytes(path)
 59→    }
 60→
 61→    fn write(&self, path: &Path, content: &[u8]) -> PraxisResult<()> {
 62→        // 1. Write to disk via LocalFs
 63→        self.local_fs.write(path, content)?;
 64→
 65→        // 2. Compute relative path for the tracker
 66→        let resolved = self.local_fs.resolve(path).ok();
 67→        let rel_path = resolved
 68→            .as_ref()
 69→            .and_then(|p| self.local_fs.relative(p))
 70→            .map(|p| format!("/{}", p.display()))
 71→            .unwrap_or_else(|| path.display().to_string());
 72→
 73→        // 3. Track the write (stores blob, updates manifest, returns event)
 74→        match self.tracker.track_write(&rel_path, content, None) {
 75→            Ok(payload) => {
 76→                // 4. Send event — non-blocking, log warning if channel is full
 77→                if let Err(e) = self.tx.try_send(payload) {
 78→                    tracing::warn!(
 79→                        path = %rel_path,
 80→                        "LagoTrackedFs: event channel full or closed, write event dropped: {e}"
 81→                    );
 82→                }
 83→            }
 84→            Err(e) => {
 85→                tracing::warn!(
 86→                    path = %rel_path,
 87→                    "LagoTrackedFs: tracker.track_write failed: {e}"
 88→                );
 89→            }
 90→        }
 91→
 92→        Ok(())
 93→    }
 94→
 95→    fn exists(&self, path: &Path) -> bool {
 96→        self.local_fs.exists(path)
 97→    }
 98→
 99→    fn metadata(&self, path: &Path) -> PraxisResult<FsMetadata> {
100→        self.local_fs.metadata(path)
101→    }
102→
103→    fn read_dir(&self, path: &Path) -> PraxisResult<Vec<FsDirEntry>> {
104→        self.local_fs.read_dir(path)
105→    }
106→
107→    fn create_dir_all(&self, path: &Path) -> PraxisResult<()> {
108→        self.local_fs.create_dir_all(path)
109→    }
110→
111→    fn relative(&self, absolute_path: &Path) -> Option<PathBuf> {
112→        self.local_fs.relative(absolute_path)
113→    }
114→}
115→
116→/// Background event writer: consumes event payloads from the channel
117→/// and appends them to the Lago journal as `EventEnvelope`s.
118→pub async fn run_event_writer(
119→    mut rx: mpsc::Receiver<EventPayload>,
120→    journal: Arc<dyn Journal>,
121→    session_id: SessionId,
122→    branch_id: BranchId,
123→) {
124→    while let Some(payload) = rx.recv().await {
125→        let envelope = EventEnvelope {
126→            event_id: EventId::new(),
127→            session_id: session_id.clone(),
128→            branch_id: branch_id.clone(),
129→            run_id: None,
130→            seq: 0,
131→            timestamp: EventEnvelope::now_micros(),
132→            parent_id: None,
133→            payload,
134→            metadata: std::collections::HashMap::new(),
135→            schema_version: 1,
136→        };
137→
138→        if let Err(e) = journal.append(envelope).await {
139→            tracing::warn!(%e, "LagoTrackedFs event writer: failed to append event");
140→        }
141→    }
142→
143→    tracing::debug!("LagoTrackedFs event writer: channel closed, shutting down");
144→}
