 77→fn unique_root(name: &str) -> PathBuf {
 78→    let nanos = SystemTime::now()
 79→        .duration_since(UNIX_EPOCH)
 80→        .map(|duration| duration.as_nanos())
 81→        .unwrap_or(0);
 82→    std::env::temp_dir().join(format!("{name}-{nanos}"))
 83→}
 84→
 85→fn build_runtime(root: PathBuf) -> Arc<KernelRuntime> {
 86→    let event_store_backend = Arc::new(FileEventStore::new(root.join("kernel")));
 87→    let journal = Arc::new(EventJournal::new(
 88→        event_store_backend,
 89→        EventStreamHub::new(1024),
 90→    ));
 91→    let event_store: Arc<dyn EventStorePort> = journal;
 92→
 93→    let policy_engine = Arc::new(SessionPolicyEngine::new(PolicySet::default()));
 94→    let policy_gate: Arc<dyn PolicyGatePort> = policy_engine.clone();
 95→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ApprovalQueue::default());
 96→
 97→    let registry = Arc::new(ToolRegistry::with_core_tools());
 98→    let sandbox = Arc::new(LocalSandboxRunner::new(vec!["echo".to_owned()]));
 99→    let dispatcher = Arc::new(ToolDispatcher::new(registry, policy_engine, sandbox));
100→    let tool_harness: Arc<dyn ToolHarnessPort> = dispatcher;
101→
102→    let provider: Arc<dyn ModelProviderPort> = Arc::new(TestProvider);
103→
104→    Arc::new(KernelRuntime::new(
105→        RuntimeConfig::new(root),
106→        event_store,
107→        provider,
108→        tool_harness,
109→        approvals,
110→        policy_gate,
111→    ))
112→}
