        "/sessions/{session_id}/branches",
        "/sessions/{session_id}/branches/{branch_id}/merge",
        "/sessions/{session_id}/approvals/{approval_id}",
    ];
    for path in expected {
        assert!(paths.contains_key(path), "missing path: {path}");
    }
}

