 215→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 216→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 217→async fn resolve_session(
 218→    data_dir: &Path,
 219→    requested: Option<String>,
 220→    base_url: Option<&str>,
 221→) -> String {
 222→    if let Some(session) = requested {
 223→        return session;
 224→    }
 225→
 226→    if let Some(session) = read_last_session_hint(data_dir) {
 227→        return session;
 228→    }
 229→
 230→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 231→    if let Some(url) = base_url {
 232→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 233→            return session;
 234→        }
 235→    }
 236→
 237→    "default".to_owned()
 238→}
