 557→        &message,
 558→        json_output,
 559→        resolved.model.as_deref(),
 560→    )
 561→    .await?;
 562→    if exit_code != 0 {
 563→        std::process::exit(exit_code);
 564→    }
 565→    Ok(())
 566→}
