 691→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 692→    // Normalize to canonical provider name for config persistence.
 693→    let canonical = match provider {
 694→        "codex" | "openai-codex" => "openai",
 695→        other => other,
 696→    };
 697→
 698→    match provider {
 699→        "openai" | "codex" | "openai-codex" => {
 700→            if device {
 701→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 702→            } else {
 703→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 704→            }
 705→        }
 706→        _ => {
 707→            return Err(anyhow::anyhow!(
 708→                "Unknown provider '{provider}'. Supported: openai"
 709→            ));
 710→        }
 711→    }
 712→
 713→    // Set the provider as the new default after successful login.
 714→    let mut file_config = config::load_config(data_dir);
 715→    file_config.set_key("provider", canonical).ok();
 716→    config::save_config(data_dir, &file_config)?;
 717→    eprintln!("Default provider set to '{canonical}'");
 718→
 719→    Ok(())
 720→}
