 774→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 775→    // Normalize provider name for credential lookup.
 776→    let normalized = match provider {
 777→        "codex" | "openai-codex" => "openai",
 778→        other => other,
 779→    };
 780→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 781→
 782→    // Clear the default provider if it matches the one being logged out.
 783→    let mut file_config = config::load_config(data_dir);
 784→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 785→        file_config.defaults.provider = None;
 786→        config::save_config(data_dir, &file_config)?;
 787→        eprintln!("Default provider cleared");
 788→    }
 789→
 790→    eprintln!("Logged out of {provider}");
 791→    Ok(())
 792→}
