 768→    pub async fn resolve_approval(
 769→        &self,
 770→        session_id: &SessionId,
 771→        approval_id: uuid::Uuid,
 772→        approved: bool,
 773→        actor: impl Into<String>,
 774→    ) -> Result<()> {
 775→        let actor = actor.into();
 776→        let resolution = self
 777→            .approvals
 778→            .resolve(
 779→                ApprovalId::from_string(approval_id.to_string()),
 780→                approved,
 781→                actor.clone(),
 782→            )
 783→            .await
 784→            .map_err(|error| anyhow::anyhow!(error.to_string()))
 785→            .with_context(|| format!("approval not pending: {approval_id}"))?;
 786→
 787→        let decision = if resolution.approved {
 788→            ApprovalDecision::Approved
 789→        } else {
