 791→        };
 792→
 793→        self.append_event(
 794→            session_id,
 795→            &BranchId::main(),
 796→            EventKind::ApprovalResolved {
 797→                approval_id: ApprovalId::from_string(approval_id.to_string()),
 798→                decision,
 799→                reason: Some(actor),
 800→            },
 801→        )
 802→        .await?;
 803→        Ok(())
