### LagoTrackedFs Implementation

**Setup in `main.rs` (lines 345-350):**
```rust
let tracker = Arc::new(FsTracker::new(Manifest::new(), blob_store.clone()));
let (fs_event_tx, fs_event_rx) = tokio::sync::mpsc::channel(1000);
let tracked_fs: Arc<dyn FsPort> = Arc::new(LagoTrackedFs::new(
    local_fs, tracker, fs_event_tx
